def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 0
        bonus = 0
        for j in range(1, 10):
            threshold = j * 0.1
            if ratio < threshold:
                increment = (10 - j) * np.log1p(capacity) * (1 + np.sin(j * np.pi / 4))
                score += increment
                if j % 3 == 0:
                    bonus += np.sqrt(capacity) / (j + 2)
                elif j % 2 == 0:
                    bonus += np.log1p(item) / (j + 1)
                else:
                    bonus += np.exp(-item / (j + 1))
            else:
                decrement = j * np.sqrt(item) * (1 + np.cos(j * np.pi / 3))
                penalty += decrement
        score = score + bonus - penalty
        if capacity < item * 1.1:
            score *= 2.0
        elif capacity < item * 1.5:
            score *= 1.5
        elif capacity > item * 5:
            score /= 3.0
        elif capacity > item * 4:
            score /= 2.0
        elif capacity > item * 3:
            score /= 1.5
        if 0.5 < ratio < 0.75:
            for k in range(5):
                score += (np.log1p(capacity) * (k + 1) / 3) - (np.sqrt(item) * np.sin(k + 1))
        elif ratio >= 0.75:
            for k in range(4):
                score += (np.log1p(capacity) / (k + 1)) - (np.sqrt(item) * (k + 1) * np.cos(k + 1))
        if score < 0:
            score = np.abs(score) / 3
        if capacity % 2 == 0:
            score += np.log1p(capacity) * 0.5
        else:
            score -= np.sqrt(capacity) * 0.3
        if item > 10 and capacity > 10:
            for m in range(1, 4):
                if (capacity / m) > item:
                    score += np.log1p(capacity / m) * np.sin(m * np.pi / 2)
                else:
                    score -= np.sqrt(item / m) * np.cos(m * np.pi / 3)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 20
    return priorities
